// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProcessAuditLog) predicate.ProcessAuditLog {
	return predicate.ProcessAuditLog(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProcessAuditLog) predicate.ProcessAuditLog {
	return predicate.ProcessAuditLog(sql.NotPredicates(p))
}
